// Hand-written service worker — intentionally NOT generated by a build plugin.
// vite-plugin-pwa / serwist do not reliably run their build hooks under
// TanStack Start's production build (Vite Environment API incompatibility),
// so this is a plain static file served as-is from `public/`, same as
// favicon.ico. Bump the version suffix below whenever cached assets change.
const VERSION = "v1";
const APP_SHELL_CACHE = `anamdev-shell-${VERSION}`;
const RUNTIME_CACHE = `anamdev-runtime-${VERSION}`;

const APP_SHELL_URLS = [
  "/offline.html",
  "/manifest.webmanifest",
  "/icons/icon-192.png",
  "/icons/icon-512.png",
  "/favicon.ico",
];

self.addEventListener("install", (event) => {
  event.waitUntil(
    caches
      .open(APP_SHELL_CACHE)
      .then((cache) => cache.addAll(APP_SHELL_URLS))
      .then(() => self.skipWaiting()),
  );
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches
      .keys()
      .then((keys) =>
        Promise.all(
          keys
            .filter((key) => key !== APP_SHELL_CACHE && key !== RUNTIME_CACHE)
            .map((key) => caches.delete(key)),
        ),
      )
      .then(() => self.clients.claim()),
  );
});

self.addEventListener("fetch", (event) => {
  const { request } = event;

  // Only handle same-origin GET requests. Everything else (Supabase REST/Auth,
  // analytics beacons, /api/* server functions, fonts CDN, POST/PUT/etc.)
  // passes straight through to the network untouched.
  if (request.method !== "GET" || new URL(request.url).origin !== self.location.origin) {
    return;
  }

  // Page navigations: network-first, falling back to the offline page.
  if (request.mode === "navigate") {
    event.respondWith(
      fetch(request).catch(() => caches.match("/offline.html")),
    );
    return;
  }

  // Static, content-hashed build assets (JS/CSS/fonts/images): cache-first,
  // since Vite's hashed filenames change on every deploy — no staleness risk.
  if (["script", "style", "font", "image"].includes(request.destination)) {
    event.respondWith(
      caches.match(request).then(
        (cached) =>
          cached ||
          fetch(request).then((response) => {
            if (response.ok) {
              const clone = response.clone();
              caches.open(RUNTIME_CACHE).then((cache) => cache.put(request, clone));
            }
            return response;
          }),
      ),
    );
  }
});
